- (RACSignal *)deleteKeySignal{
    if ([CTMediator isSDK2ndCar]) {
        return [self deleteKeySignalInner2nd];
    }
    @weakify(self);
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);
        XPBLEKeyCard *card = XPBLEKeyManager.instance.defaultCard;
        if(!card || card.status == XPBLEKeyCardStatusInvalid){
            [subscriber sendCompleted];
            return nil;
        }

        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        [disposable addDisposable:[[RACSignal.never timeout:20 onScheduler:RACScheduler.scheduler] subscribeError:^(NSError * _Nullable error) {
            [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeDeleteSafeKeyTimeout userInfo:nil]];
        }]];

        if (![card.deviceId isEqualToString:UIDevice.devideId]) {
            [disposable addDisposable:[[[XPBLEKeyManager.instance.requestCancelShareCardCommand execute:@[card.cardNo]] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
                DLogTagInfo(kBLEKeyTag, @"删除蓝牙钥匙失败:%@",error.localizedFailureReason);
                [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeDeleteSafeKeyFail userInfo:nil]];
            } completed:^{
                @strongify(self)
                DLogTagInfo(kBLEKeyTag, @"申请删除成功");
                [card markAsRemoving];
                [[XPBLEKeyManager.instance viewModelWithVin:self.carInfo.vin] refeshList];
                [subscriber sendCompleted];
            }]];
        }else{
            [disposable addDisposable:[[[XPBLEKeyManager.instance.destoryBLEKeyCommand execute:card.cardNo] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
                DLogTagError(kBLEKeyTag, @"%@",error);

                [disposable addDisposable:[[[XPBLEKeyManager.instance.requestDestroyCardInThisDeviceCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
                    DLogTagInfo(kBLEKeyTag, @"注销失败%@", error);
                    [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeDeleteSafeKeyFail userInfo:nil]];
                } completed:^{
                    @strongify(self)
                    DLogTagInfo(kBLEKeyTag, @"申请注销成功");
                    [card markAsRemoving];
                    [[XPBLEKeyManager.instance viewModelWithVin:self.carInfo.vin] refeshList];
                    [subscriber sendCompleted];
                }]];
            } completed:^{
                DLogTagInfo(kBLEKeyTag, @"申请注销成功");
                [card markAsRemoving];
                [subscriber sendCompleted];
            }]];
        }
        return nil;
    }];
}

- (RACSignal *)createKeySignal{
    if ([CTMediator isSDK2ndCar]) {
        return [self createKeySignalInner2nd];
    }
    @weakify(self);
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);

        DLogTagInfo(kBLEKeyTag, @"isSupportIFAA is %d, 用户%@面容权限", [EtasManager isSupportIFAA], [EtasManager hasPermissionForFaceID]?@"拥有":@"不拥有");
        if(![self.laContext canEvaluatePolicy:LAPolicyDeviceOwnerAuthenticationWithBiometrics error:nil]) {
            [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeNoIdPermission userInfo:nil]];
            return nil;
        }

        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        [disposable addDisposable:[[RACSignal.never timeout:40 onScheduler:RACScheduler.scheduler] subscribeError:^(NSError * _Nullable error) {
            [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeCreateSafeKeyTimeout userInfo:nil]];
        }]];

        __block NSString *cardNo;
        @weakify(disposable);
        [disposable addDisposable:[[self createKeyCardSignal] subscribeNext:^(id  _Nullable x) {
            cardNo = x;
        } error:^(NSError * _Nullable error) {
            [subscriber sendError:error];
        } completed:^{
            @strongify(disposable);
            @strongify(self)
            [disposable addDisposable:[[self activateCardSignalWithCardNo:cardNo] subscribeNext:^(id  _Nullable x) {

            } error:^(NSError * _Nullable error) {
                [subscriber sendError:error];
            } completed:^{
                [subscriber sendCompleted];
            }]];
        }]];

        return disposable;
    }];
}

- (RACSignal *)createKeyCardSignal{
    if ([CTMediator isSDK2ndCar]) {
        return [self createKeyCardSignalInner2nd];
    }
    @weakify(self);
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);
        RACDisposable *disposable = nil;
        if(self.shareFromUid){
            DLogTagInfo(kBLEKeyTag, @"创建蓝牙钥匙，是被分享者，调用被分享者的创建接口");
            //如果是被分享者，则调用被分享者的创建接口
            disposable = [[XPBLEKeyManager.instance.requestCreatKeyCardByReceiverCommand execute:@{@"vin":self.carInfo.vin?:@"", @"shareFrom":@(self.shareFromUid), @"cardType":@(XPBLEKeyCardType_BLEKey)}] subscribeNext:^(id  _Nullable x) {
                DLogTagInfo(kBLEKeyTag, @"requestCreatBLEKeyCarCommand success,%@",x);
                [subscriber sendNext:x];
            } error:^(NSError * _Nullable error) {
                [XPCarStatisticsManager.sharedInstance addEvent:[XPCarStatisticsEvent eventWithPageId:XP_MOBILE_CARCONTROL_MODULE buttonId:XP_MOBILE_CARCONTROL_CREATBLEKEY error:[NSError errorWithDomain:@"JRCreateKeyErrorDomain" code:error.code userInfo:nil]]];
                DLogTagError(kBLEKeyTag,@"requestCreatBLEKeyCarCommand error=%@",error);
                if (XPCreateKeyErrorCodeFailToAuthorizationFull != error.code) {
                    DLogTagInfo(kBLEKeyTag, @"蓝牙数字钥匙创建失败:%@", error.userInfo[@"msg"]);
                    [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeFailToCreateSafeKeyCard userInfo:nil]];
                } else {
                    DLogTagInfo(kBLEKeyTag, @"无法继续添加蓝牙钥匙，已经超出当前支持的蓝牙钥匙总数");
                    [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeFailToAuthorizationFull userInfo:nil]];
                }
            } completed:^{
                [subscriber sendCompleted];
            }];
        }else{
            DLogTagInfo(kBLEKeyTag, @"创建蓝牙钥匙，是车主，调用车主的创建接口");
            //如果是车主，则调用车主的创建接口
            [[XPBLEKeyManager.instance.requestCreatBLEKeyCardCommand execute:@{@"vin":self.carInfo.vin}] subscribeNext:^(id  _Nullable x) {
                DLogTagInfo(kBLEKeyTag, @"requestCreatBLEKeyCarCommand success,%@",x);
                [subscriber sendNext:x];
            } error:^(NSError * _Nullable error) {
                [XPCarStatisticsManager.sharedInstance addEvent:[XPCarStatisticsEvent eventWithPageId:XP_MOBILE_CARCONTROL_MODULE buttonId:XP_MOBILE_CARCONTROL_CREATBLEKEY error:[NSError errorWithDomain:@"JRCreateKeyErrorDomain" code:error.code userInfo:nil]]];
                DLogTagError(kBLEKeyTag,@"requestCreatBLEKeyCarCommand error=%@",error);
                if (XPCreateKeyErrorCodeFailToAuthorizationFull != error.code) {
                    DLogTagInfo(kBLEKeyTag, @"蓝牙数字钥匙创建失败:%@", error.userInfo[@"msg"]);
                    [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeFailToCreateSafeKeyCard userInfo:nil]];
                } else {
                    DLogTagInfo(kBLEKeyTag, @"无法继续添加蓝牙钥匙，已经超出当前支持的蓝牙钥匙总数");
                    [subscriber sendError:[NSError errorWithDomain:XPCreateKeyErrorDomain code:XPCreateKeyErrorCodeFailToAuthorizationFull userInfo:nil]];
                }
            } completed:^{
                [subscriber sendCompleted];
            }];
        }
        return disposable;
    }];
}

